use std::collections::HashMap;

fn gcd(a: u32, b: u32) -> u32 {
    if b == 0 { a } else { gcd(b, a % b) }
}

fn solve(points: Vec<Vec<i64>>) -> i64 {
    let n = points.len();
    let mut slope_groups: HashMap<(i64, i64), HashMap<i64, i64>> = HashMap::new();
    let mut mid_map: HashMap<(i64, i64), Vec<(usize, usize)>> = HashMap::new();

    for i in 0..n {
        for j in (i + 1)..n {
            let dx = points[j][0] - points[i][0];
            let dy = points[j][1] - points[i][1];
            let slope = if dx == 0 {
                (0, 1)
            } else if dy == 0 {
                (1, 0)
            } else {
                let dx_abs = dx.abs() as u32;
                let dy_abs = dy.abs() as u32;
                let g = gcd(dx_abs, dy_abs) as i64;
                let mut dx_n = dx / g;
                let mut dy_n = dy / g;
                if dy_n < 0 {
                    dx_n = -dx_n;
                    dy_n = -dy_n;
                }
                (dx_n, dy_n)
            };

            let intercept = slope.1 * points[i][0] - slope.0 * points[i][1];
            *slope_groups
                .entry(slope)
                .or_insert_with(HashMap::new)
                .entry(intercept)
                .or_insert(0) += 1;

            let mid_x = points[i][0] + points[j][0];
            let mid_y = points[i][1] + points[j][1];
            mid_map.entry((mid_x, mid_y))
                .or_insert_with(Vec::new)
                .push((i, j));
        }
    }

    let mut total_trap = 0;
    for (_, intercept_map) in slope_groups.iter() {
        let k: i64 = intercept_map.values().sum();
        let mut same_inter_pair_cnt = 0;
        for &cnt in intercept_map.values() {
            same_inter_pair_cnt += cnt * (cnt - 1) / 2;
        }
        total_trap += k * (k - 1) / 2 - same_inter_pair_cnt;
    }

    let mut total_par = 0;
    for (_, segments) in mid_map.iter() {
        let k = segments.len() as i64;
        if k < 2 {
            continue;
        }
        let mut deg = vec![0; n];
        for &(i, j) in segments.iter() {
            deg[i] += 1;
            deg[j] += 1;
        }
        let mut bad_pairs = 0;
        for &d in deg.iter() {
            if d >= 2 {
                bad_pairs += d * (d - 1) / 2;
            }
        }
        total_par += k * (k - 1) / 2 - bad_pairs;
    }

    total_trap - total_par
}
