fn normalize_slope(dx: i64, dy: i64) -> (i64, i64) {
    if dx == 0 && dy == 0 {
        return (0, 0);
    }
    let abs_dx = dx.abs() as u64;
    let abs_dy = dy.abs() as u64;
    let g = gcd(abs_dx, abs_dy) as i64;
    let mut dx0 = dx / g;
    let mut dy0 = dy / g;
    if dx0 < 0 || (dx0 == 0 && dy0 < 0) {
        dx0 = -dx0;
        dy0 = -dy0;
    }
    (dx0, dy0)
}

fn solve(points: Vec<Vec<i64>>) -> i64 {
