    let mut slope_map: HashMap<(i64, i64), HashMap<i64, usize>> = HashMap::new();

    for i in 0..n {
        for j in (i + 1)..n {
            let p0 = &points[i];
            let p1 = &points[j];
            let x0 = p0[0];
            let y0 = p0[1];
            let x1 = p1[0];
            let y1 = p1[1];
            let dx = x1 - x0;
            let dy = y1 - y0;
            let (dx0, dy0) = normalize_slope(dx, dy);
            if dx0 == 0 && dy0 == 0 {
                continue;
            }
            let intercept = if dx0 == 0 {
                x0
            } else {
                dy0 * x0 - dx0 * y0
            };
            let group = slope_map.entry((dx0, dy0)).or_insert_with(HashMap::new);
            *group.entry(intercept).or_insert(0) += 1;
        }
    }

    let mut T = 0i64;
    for group_map in slope_map.values() {
        let total_edges: usize = group_map.values().sum();
        if total_edges < 2 {
            continue;
        }
        let within_line_pairs: i64 = group_map.values().map(|&cnt| (cnt * (cnt - 1) / 2) as i64).sum();
        let total_pairs = (total_edges * (total_edges - 1) / 2) as i64;
        T += total_pairs - within_line_pairs;
    }

    let mut mid_map: HashMap<(i64, i64), usize> = HashMap::new();
    for i in 0..n {
        for j in (i + 1)..n {
            let p0 = &points[i];
            let p1 = &points[j];
            let x0 = p0[0];
            let y0 = p0[1];
            let x1 = p1[0];
            let y1 = p1[1];
            let mid = (x0 + x1, y0 + y1);
            *mid_map.entry(mid).or_insert(0) += 1;
        }
    }

    let parallelogram_count: i64 = mid_map.values().map(|&cnt| (cnt * (cnt - 1) / 2) as i64).sum();

    T - parallelogram_count
}
