        let mut adjacent_pairs = 0;
        if let Some(deg_map) = mid_deg.get(&mid) {
            for &d in deg_map.values() {
                adjacent_pairs += d * (d - 1) / 2;
            }
        }
        G += total_pairs - adjacent_pairs;
    }

    T - G
